#include <iostream>
#include <string>

class Employee {
    std::string name_;
    int salary_;
public:
    Employee(std::string n, int s) : name_{std::move(n)}, salary_{s} {}
    const std::string& name()   const { return name_; }
    int                salary() const { return salary_; }
};

class Manager : public Employee {
    int teamSize_;
public:
    Manager(std::string n, int s, int ts)
        : Employee{std::move(n), s}, teamSize_{ts} {}
    int teamSize() const { return teamSize_; }
};

void printRecord(const Employee& e, bool isManager, int teamSize) {
    if (isManager) {
        std::cout << "Manager: " << e.name() << " salary=" << e.salary()
                  << " team=" << teamSize << "\n";
    } else {
        std::cout << "Employee: " << e.name() << " salary=" << e.salary() << "\n";
    }
}

int main() {
    int n{};
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        char type{};
        std::string nm;
        int sal{};
        std::cin >> type >> nm >> sal;
        if (type == 'E') {
            Employee e{nm, sal};
            printRecord(e, false, 0);
        } else {
            int ts{};
            std::cin >> ts;
            Manager m{nm, sal, ts};
            printRecord(m, true, ts);
        }
    }
    return 0;
}
